eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   units: () => (/* binding */ units)\n/* harmony export */ });\nconst units = [\n    {\n        id: 1,\n        week: 1,\n        title: \"فرصة البزنس الأونلاين في السودان ومهاراته الأساسية\",\n        duration: \"90 دقيقة\",\n        icon: \"TrendingUp\",\n        objective: \"بنهاية هذه الوحدة، تكون قادراً على شرح سبب نمو فرصة التجارة الرقمية في السودان بالأرقام، وتحديد المهارات الثلاث التي تحتاج تطويرها، وتكون قد كتبت أول تقييم ذاتي لجاهزيتك لبدء مشروعك.\",\n        tip: \"لا تنتظر أن يكتمل كل شيء لتبدأ. السوق يعلّمك أكثر مما تعلّمك القراءة وحدها.\",\n        expertTip: \"لا تستخدم أي مصطلح إنجليزي في البداية — ترجم كل شيء لعربية بسيطة جداً. بيئة السوق السوداني لها خصوصية: انقطاع الكهرباء والإنترنت المتكرر، محدودية وسائل الدفع الإلكتروني، والاعتماد شبه الكامل على الدفع عند الاستلام.\",\n        openingScript: \"من منكم اشترى شيئاً عبر فيسبوك أو تيك توك أو واتساب الأسبوع الماضي؟ اجعل نفسك تكتشف أنك جزء من هذا السوق فعلاً، قبل أن تنظر إلى الأرقام.\",\n        sections: [\n            {\n                heading: \"لماذا الآن؟ — الأرقام تتكلم\",\n                body: \"بلغ عدد مستخدمي الإنترنت في السودان 14.6 مليون شخص بنسبة اختراق 28.7%، ووصل عدد مستخدمي التواصل الاجتماعي إلى 3.68 مليون هوية بنمو 26.3% خلال عام واحد فقط. فيسبوك يهيمن بنسبة 73.75% من مستخدمي التواصل الاجتماعي، يليه يوتيوب 10.44% ثم إكس 7.45%، بينما تيك توك يسجل أسرع نمو نسبي بين كل المنصات. الاتصالات الخلوية تجاوزت 21.6 مليون خط مشغول، ما يعني أن واتساب هو القناة الأقرب لجيب كل عميل محتمل تقريباً. هذه الأرقام ليست إحصائيات فقط، بل خريطة توضح لك أين يوجد عملاؤك وكيف تصل إليهم: ابدأ بفيسبوك كقاعدة أساسية، استثمر مبكراً في تيك توك لأنه الأسرع نمواً، واعتبر واتساب متجرك المصغر في جيب كل عميل.\"\n            },\n            {\n                heading: \"لماذا يناسب البزنس الأونلاين المبتدئ السوداني تحديداً\",\n                body: \"رأس مال منخفض: يمكنك البدء بدون محل أو مخزون كبير، وأحياناً ببضائع طلب مسبق فقط — تتواصل مع المورد فقط بعد أن يطلب العميل. مرونة كاملة في الزمان والمكان: مهمة جداً في ظل تقلبات الكهرباء والمواصلات، فتدير مشروعك من أي مكان وفي أي وقت تتوفر فيه الكهرباء أو الإنترنت. قابلية التوسع التدريجي: تبدأ بمنتج واحد وتضيف حسب الطلب الفعلي لا التخمين. تعدد مصادر الدخل: بيع مباشر، تسويق بالعمولة، أو خدمة رقمية كالتصميم أو إدارة الصفحات للآخرين.\"\n            },\n            {\n                heading: \"المهارات الثلاث التي يبنيها هذا المنهج\",\n                body: \"المهارة الأولى: التسويق الرقمي وفهم أساسيات خوارزميات المنصات — فهم لماذا يظهر منشور لآلاف ولا يظهر آخر هو الفرق بين أن تنشر وتنتظر، وبين أن تنشر وتصل. المهارة الثانية: إنشاء محتوى جذاب بالصورة والفيديو باستخدام الهاتف فقط — المحتوى الجيد هو العملة الأساسية في التجارة الرقمية. المهارة الثالثة: خدمة العملاء وإدارة المحادثات بسرعة واحترافية — العميل لا يشتري المنتج فقط، بل يشتري الثقة فيك، وسرعة الرد هي ما يبني تلك الثقة.\"\n            }\n        ],\n        caseStudy: {\n            title: \"من هامش الوقت إلى دخل ثابت\",\n            story: \"متدربة في الخرطوم كانت تعمل موظفة إدارية، بدأت ببيع العطور الفرنسية المقلدة عالية الجودة عبر صفحة فيسبوك بسيطة أنشأتها في مساء واحد. في الشهر الأول لم تنفق أي مبلغ على إعلانات، بل اعتمدت على مشاركة الصفحة في مجموعات نسائية والنشر اليومي المنتظم. كانت ترد على كل استفسار خلال دقائق حتى في العمل. خلال شهرين تجاوز دخلها راتبها السابق واستقالت للتفرغ لمشروعها.\",\n            analysis: \"ثلاثة عوامل متكاملة: الاستمرارية في النشر اليومي أبقت الصفحة حية في الخوارزمية، الرد السريع بنى ثقة فورية، والاعتماد على المجموعات النسائية كقناة مجانية بدل الإعلانات المدفوعة في البداية. نموذج يمكن لأي شخص تكراره لأنه لا يتطلب رأس مال كبير ولا خبرة تقنية.\"\n        },\n        goldenRule: \"لا تنتظر أن يكتمل كل شيء لتبدأ، ابدأ بصفحة بسيطة ومنتج واحد، فالسوق يعلّمك أكثر مما تعلّمك القراءة وحدها.\",\n        commonMistake: {\n            problem: \"الانشغال الطويل بالتخطيط النظري والقراءة عن التجارة الإلكترونية دون تنفيذ أي خطوة فعلية لأسابيع، بحجة \\\"مش جاهز بعد\\\".\",\n            solution: \"حدد سقفاً زمنياً للتحضير لا يتجاوز أسبوعاً واحداً، وبعده يجب أن تكون قد نشرت أول منشور فعلي، مهما كان بسيطاً. النشر يعلمك أكثر من أي قراءة.\"\n        },\n        exercises: [\n            {\n                title: \"تشخيص جاهزيتي\",\n                description: \"أي مهارة من المهارات الثلاث (تسويق رقمي، إنشاء محتوى، خدمة عملاء) أملكها فعلاً؟ أيها أحتاج تعلمها من الصفر؟ كم ساعة أسبوعياً أستطيع تخصيصها بصدق؟\",\n                format: \"نصي\"\n            },\n            {\n                title: \"خريطة المنصات الثلاث\",\n                description: \"اكتب تحت كل منصة ماذا سيفعل بها عميلك المستقبلي: تيك توك (اكتشاف؟)، فيسبوك (ثقة؟)، واتساب (شراء؟).\",\n                format: \"نصي\"\n            },\n            {\n                title: \"محاكاة سريعة — تحليل منافس\",\n                description: \"افتح فيسبوك الآن وابحث عن صفحتين تبيعان في مجالك التقريبي. اكتب ملاحظة واحدة عن كل صفحة: ما الذي أعجبك وما الذي تراه ضعيفاً؟\",\n                format: \"نصي\"\n            }\n        ],\n        expectedQuestions: [\n            {\n                q: \"أنا لا أملك رأس مال، هل يمكنني البدء فعلاً؟\",\n                a: \"نعم، ابدأ بمنتج طلب مسبق (لا تشتري مخزوناً) أو بخدمة رقمية كالتصميم لا تحتاج رأس مال أصلاً.\"\n            },\n            {\n                q: \"هل أحتاج جهاز كمبيوتر؟\",\n                a: \"لا، الهاتف الذكي كافٍ تماماً لكل ما ستتعلمه في هذه الورشة.\"\n            }\n        ],\n        aiPrompt: \"أنا أريد بدء مشروع تجارة إلكترونية صغير في السودان. مجالي التقريبي هو [اكتب مجالك]. ساعدني في: 1) تحديد 3 منتجات محددة يمكنني البدء بها. 2) كتابة فقرة قصيرة (3 أسطر) تصف مزايا كل منتج. 3) اقتراح اسم بسيط وجذاب لصفحتي على فيسبوك. 4) كتابة أول منشور تعريفي للصفحة.\",\n        homework: \"اكتب صفحة واحدة تلخص: مجالك التقريبي المفضّل، ثلاث نقاط قوة شخصية تخدم هذا المجال، وساعات العمل الأسبوعية المتاحة لديك بصدق.\",\n        tool: {\n            name: \"Google Sheets\",\n            description: \"لإنشاء جدول تتبع بسيط لأفكار المنتجات والملاحظات التي تجمعها من الصفحات المنافسة. مجاني ويعمل على الهاتف مباشرة.\",\n            url: \"https://sheets.google.com\"\n        },\n        selfCheck: [\n            \"أستطيع ذكر نسبة انتشار الإنترنت في السودان تقريباً (حوالي 28.7%)\",\n            \"أعرف أي منصة تسيطر على السوق السوداني (فيسبوك 73.75%)\",\n            \"حددت المنصة التي سأبدأ بها أولاً\",\n            \"أستطيع ذكر المهارات الثلاث الأساسية\",\n            \"كتبت 3 نقاط قوة شخصية تخدم مشروعي\",\n            \"أنجزت واجب هذه الوحدة\"\n        ],\n        projectComponent: \"لا يوجد مكوّن ملموس بعد؛ هذه الوحدة تأسيسية فقط لتحديد المسار ونية المشروع.\",\n        pathNotes: {\n            beginner: \"لا تستخدم أي مصطلح إنجليزي في هذه الجلسة، ترجم كل شيء لعربية بسيطة جداً، فأي مصطلح غريب يخيفك من الاستمرار.\",\n            intermediate: \"اربط الأرقام بمقارنة سريعة مع مجالك تحديداً: كم صفحة تعرفها في مجالك؟ هذا يحفّز التفكير التحليلي المبكر.\",\n            professional: \"لن نُطل هنا؛ هذه الأرقام قد تعرفها غالباً. المهم أن تحدد ميزانيتك التسويقية المتاحة الآن.\"\n        }\n    },\n    {\n        id: 2,\n        week: 1,\n        title: \"اختيار المجال والمنتج واختبار الفكرة\",\n        duration: \"90 دقيقة\",\n        icon: \"Target\",\n        objective: \"بنهاية هذه الوحدة، تكون قد اخترت مجالاً ومنتجاً أولياً محدداً، وحللت منافسَين حقيقيين، وصممت طريقة بسيطة لاختبار الطلب قبل إنفاق أي مبلغ حقيقي.\",\n        tip: \"80% من النجاح في اختيار المنتج الصحيح، لا في جودة الإعلان لاحقاً.\",\n        expertTip: \"التعاون مع أصحاب صفحات صغيرة في مجال مكمّل (لا منافس) لتبادل الترويج مجاناً هو أرخص وسيلة لجمع أول عملاء حقيقيين.\",\n        openingScript: \"لا تسمح لنفسك بإنهاء هذه الوحدة دون اسم منتج محدد واحد مكتوب أمامك.\",\n        sections: [\n            {\n                heading: \"معايير اختيار المجال — المعايير الأربعة\",\n                body: \"المعيار الأول: مجال تفهمه أو تحبه — المعرفة الشخصية تعطيك ميزة في فهم ما يريده العميل بالضبط. المعيار الثاني: حجم طلب حقيقي في السوق السوداني — ابحث عن صفحات ناجحة في نفس المجال؛ إن وجدتها فالطلب موجود. المعيار الثالث: سهولة التوصيل والشحن — اختر منتجاً صغيراً وخفيفاً وغير قابل للكسر، مع مدة صلاحية طويلة إن أمكن. المعيار الرابع: هامش ربح مناسب يغطي المجهود — احسب سعر البيع ناقص سعر الشراء ناقص تكلفة التوصيل؛ إذا كان الهامش أقل من 30% ففكر في منتج آخر.\"\n            },\n            {\n                heading: \"أفضل المجالات في السوق السوداني حالياً\",\n                body: \"المنتجات الرقمية (دورات، قوالب، كتب إلكترونية): تكلفة تشغيل شبه معدومة وتعمل حتى مع انقطاع الإنترنت لأن المشتري يحملها مرة واحدة. المنتجات المحلية (عطور، ملابس تقليدية، حرف يدوية): طلب مستمر والمنتج السوداني الأصلي يلقى إقبالاً أفضل من المستورد. المنتجات الاستهلاكية (تجميل، مكملات، أجهزة صغيرة): شراء متكرر يضمن دخلاً مستمراً لكن يتطلب سمعة جودة جيدة. الخدمات الرقمية (تصميم، إدارة صفحات، استيراد وتوصيل): بدون أي رأس مال للمنتجات.\"\n            },\n            {\n                heading: \"تحليل المنافسة واختبار الفكرة قبل الاستثمار\",\n                body: \"قبل الدخول في أي مجال، اجمع عن منافسيك: عدد المتابعين (مؤشر لحجم السوق)، نوع المحتوى الذي ينشرونه، آخر 3 أسعار ظهرت لهم، وتقييمات عملائهم. ثم اختبر فكرتك قبل إنفاق أي مبلغ كبير بثلاث طرق: الاستطلاع البسيط (سؤال 5-10 معارف بصدق)، النشر التجريبي (نشر صور المنتج في مجموعات ومراقبة ردة الفعل)، أو طلب كمية تجريبية صغيرة (حتى 5 قطع فقط) إذا احتاج المنتج استيراداً.\"\n            }\n        ],\n        caseStudy: {\n            title: \"الفكرة التي فشلت قبل أن تختبر\",\n            story: \"شاب في مدني استثمر كامل مدخراته (أكثر من مليون جنيه) في استيراد جهاز إلكتروني اعتماداً على إعجابه الشخصي، دون أن يسأل أي عميل محتمل. بعد وصول الشحنة اكتشف أن السعر أعلى بكثير مما يقبله السوق المحلي، وباع 3 أجهزة فقط خلال شهرين، مضطراً لبيع الباقي بخسارة كبيرة.\",\n            analysis: \"السبب المباشر هو غياب اختبار الفكرة قبل الاستثمار الكامل. لو نشر صورة الجهاز في مجموعات واتساب وسأل عن السعر المقبول، لتجنّب معظم الخسارة. الخطأ لم يكن في المنتج بل في طريقة الدخول: استثمار كبير بناءً على افتراض شخصي دون دليل من السوق.\"\n        },\n        goldenRule: \"لا تشترِ الكمية الكبيرة إلا بعد أن يشتري منك 5 غرباء حقيقيين على الأقل، فرأي الأصدقاء والأهل لا يُعتد به وحده لأنهم قد يجاملونك.\",\n        commonMistake: {\n            problem: \"اختيار المنتج بناءً على الإعجاب الشخصي فقط دون التحقق من وجود طلب حقيقي أو منافسة صحية في السوق المحلي.\",\n            solution: \"اطبّق دائماً قاعدة الدليل الخارجي: قبل الاستثمار، تأكد من وجود دليل واحد على الأقل على الطلب — منافسون ناجحون فعلاً، أو ردود إيجابية على استطلاع حقيقي من أشخاص لا يعرفونك شخصياً.\"\n        },\n        exercises: [\n            {\n                title: \"اختر منتجك الآن — كن محدداً\",\n                description: \"اكتب اسم منتج أو خدمة واحدة محددة (ليس مجالاً عاماً)، ثم 3 أسباب واضحة تجعل شخصاً في مدينتك يشتري هذا المنتج تحديداً منك.\",\n                format: \"نصي\"\n            },\n            {\n                title: \"تشريح منافس حقيقي\",\n                description: \"سجّل: عدد متابعيه، آخر 3 أسعار ظهرت له، وأفضل منشور من حيث التفاعل ولماذا برأيك نجح.\",\n                format: \"نصي\"\n            },\n            {\n                title: \"تصميم استطلاع اختبار الطلب\",\n                description: \"اكتب رسالة واتساب قصيرة (لا تتجاوز 3 أسطر) تسأل بها 5 معارف عن رأيهم في منتجك المقترح وسعره. أرسلها فعلياً وسجّل الردود.\",\n                format: \"نصي\"\n            }\n        ],\n        expectedQuestions: [\n            {\n                q: \"عندي أكثر من فكرة، أيها أختار؟\",\n                a: \"اختر الفكرة التي تستطيع اختبارها بأقل تكلفة هذا الأسبوع، لا الفكرة الأكبر ربحاً نظرياً.\"\n            },\n            {\n                q: \"منافسي كثيرون جداً في هذا المجال، هل أستمر؟\",\n                a: \"وجود منافسين كثر دليل على وجود طلب حقيقي، ركّز على ميزة تفصيلية صغيرة تميزك عنهم بدل الهروب من المجال.\"\n            }\n        ],\n        aiPrompt: \"أريد أن أبيع [اسم المنتج المحدد] في [مدينتك] عبر فيسبوك وواتساب. ساعدني في: 1) كتابة 5 أسباب تجعل هذا المنتج مطلوباً في السودان. 2) اقتراح 3 أسماء بديلة للمنتج تناسب السوق السوداني. 3) كتابة رسالة واتساب قصيرة لاختبار رد فعل الناس. 4) تحديد 3 مزايا تنافسية يمكنني تقديمها.\",\n        homework: \"نفّذ استطلاع اختبار الطلب الفعلي: أرسل رسالة واتساب لـ5 أشخاص على الأقل، اجمع الردود، واكتب قرارك: هل تواصل أم تعدل الفكرة أم تغيرها؟\",\n        tool: {\n            name: \"Facebook Ads Library\",\n            description: \"أداة مجانية تتيح رؤية كل الإعلانات النشطة لأي صفحة منافسة، مفيدة لفهم استراتيجية المنافسين مباشرة.\",\n            url: \"https://facebook.com/ads/library\"\n        },\n        selfCheck: [\n            \"أستطيع ذكر المعايير الأربعة لاختيار المجال الصحيح\",\n            \"اخترت منتجاً محدداً واحداً (ليس مجالاً عاماً)\",\n            \"حللت منافساً واحداً على الأقل وسجلت المعلومات الأساسية\",\n            \"صممت رسالة استطلاع وأرسلتها لـ3 أشخاص على الأقل\",\n            \"أستطيع شرح لماذا اختبار الفكرة يوفر المال\",\n            \"أنجزت واجب هذه الوحدة (تقرير استطلاع اختبار الطلب)\"\n        ],\n        projectComponent: \"أول لبنة في المتجر: اسم المنتج النهائي مكتوباً ومعتمداً، وقائمة 3 منافسين حقيقيين ستتابعهم طوال الورشة.\",\n        pathNotes: {\n            beginner: \"امنع نفسك تماماً من التفكير في أكثر من منتج واحد. كرر جملة \\\"منتج واحد فقط\\\"، فالتشتت هو أكبر عدو لهذا المستوى تحديداً.\",\n            intermediate: \"حلّل منافساً واحداً بعمق أكبر (تسعير، تعليقات العملاء) بدل تحليل سطحي لعدة منافسين.\",\n            professional: \"أجرِ اختبار طلب حقيقي (استطلاع مدفوع صغير أو Boost بسيط) بدل الاكتفاء بالاستطلاع المجاني في المجموعات.\"\n        }\n    }\n];\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./src/data/units-1-2.ts\n");

