eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   units34: () => (/* binding */ units34)\n/* harmony export */ });\nconst units34 = [\n    {\n        id: 3,\n        week: 2,\n        title: \"بناء صفحة فيسبوك احترافية ومحتواها\",\n        duration: \"90 دقيقة\",\n        icon: \"Facebook\",\n        objective: \"بنهاية هذه الوحدة، تكون قد أنشأت أو حسّنت صفحة فيسبوك كاملة العناصر، وجهّزت جدول نشر أسبوعي، وأنتجت أول منشور احترافي بنفسك.\",\n        tip: \"خوارزمية فيسبوك تفضّل المنشورات التي تولّد تعليقات حقيقية في أول 30 دقيقة من نشرها، فاطلب رأياً مباشراً بدل طلب لايك فقط.\",\n        expertTip: \"خوارزمية فيسبوك تفضّل المنشورات التي تولّد تعليقات حقيقية (لا إعجابات فقط) في أول 30 دقيقة من نشرها.\",\n        openingScript: \"هذه الوحدة عملية بالكامل. لا تشرح لنفسك أكثر من 10 دقائق نظرياً، ثم افتح هاتفك فوراً. الهدف أن ترى صفحتك أمامك قبل نهاية الجلسة.\",\n        sections: [\n            {\n                heading: \"عناصر الصفحة الاحترافية — الانطباع الأول يبيع\",\n                body: \"فيسبوك يهيمن على 73.75% من استخدام التواصل الاجتماعي في السودان، لذا فهو البوابة الرئيسية لأي مشروع. الزائر يحتاج ثانيتين فقط ليقرر المتابعة أو الخروج. الاسم التجاري: واضح وسهل الحفظ (\\\"عطور نسمة الخرطوم\\\" أفضل من \\\"Beauty World Store\\\"). الصورة الشخصية: شعارك أو أفضل صورة لمنتجك الرئيسي، تظهر بجانب كل تعليق. الغلاف: أكبر مساحة بصرية، يجب أن يخبر الزائر بثلاثة أشياء في لمحة: ماذا تبيع، لمن، وما الميزة. قسم النبذة: جملتان فقط تتضمن ماذا تبيع، لمن، وما يميزك، بكلمات مفتاحية يبحث عنها الناس.\"\n            },\n            {\n                heading: \"قواعد المحتوى — ما ينشره الناس ويتفاعلون معه\",\n                body: \"الصور: عالية الجودة وبإضاءة جيدة؛ خلفية بيضاء نظيفة أفضل من صورة مزدحمة. الفيديوهات: مدتها بين 30 و60 ثانية، وابدأ بجملة جذابة في أول 3 ثوانٍ بدل الترحيب. التنويع: قاعدة 70/30 — 70% محتوى قيم (نصائح، تجارب) و30% بيع مباشر فقط، لأن الناس تتابع صفحة للفائدة لا للإعلانات. البث المباشر: استخدمه أسبوعياً على الأقل، فهو يحصل على أولوية في الخوارزمية ويصل لأشخاص جدد.\"\n            },\n            {\n                heading: \"جدول المحتوى الأسبوعي المقترح\",\n                body: \"الأحد: نصيحة أو معلومة قيمة تثبت خبرتك. الاثنين: عرض منتج جديد بصورة جذابة وسعر واضح. الثلاثاء: مراجعة أو تجربة عميل حقيقية. الأربعاء: محتوى خلف الكواليس يثبت أن مشروعك حقيقي. الخميس: عرض خاص أو خصم لمدة 24 ساعة فقط. الجمعة: محتوى تفاعلي (استطلاع أو سؤال) لأن التفاعل في أول 30 دقيقة يحدد وصول المنشور. السبت: ملخص أسبوعي أو توقعات.\"\n            }\n        ],\n        caseStudy: {\n            title: \"صفحة بلا هوية مقابل صفحة متكاملة\",\n            story: \"متجر ملابس في بورتسودان كانت صفحته فوضوية: بدون غلاف، صورة شخصية عادية، نبذة فارغة، ونشر غير منتظم. بعد 3 أشهر لم يتجاوز متابعوه 200 شخص. بعد إعادة بناء الصفحة بالكامل بغلاف احترافي ونبذة واضحة وجدول نشر يومي ثابت، تضاعف عدد المتابعين لأكثر من 800 خلال 3 أسابيع، وزادت الاستفسارات اليومية من 1-2 إلى 8-10 رسائل.\",\n            analysis: \"الفارق لم يكن في المنتج بل في الطريقة التي يُرى بها المشروع. صفحة مرتبة تعطي شعوراً بالاحترافية يحوّل المتصفح إلى متابع ومشتري محتمل، والنشر اليومي المنتظم أبقى الصفحة حية في الخوارزمية.\"\n        },\n        goldenRule: \"لا تبدأ الإعلانات المدفوعة قبل أن تنشر عضوياً 20 منشوراً على الأقل، فالإعلان يضخم صفحة قوية كما يضخم صفحة ضعيفة.\",\n        commonMistake: {\n            problem: \"تحويل الصفحة إلى لوحة إعلانات متواصلة: منتج وسعر واطلب الآن، دون أي محتوى قيم، مما يجعل المتابعين يشعرون بالملل.\",\n            solution: \"التزم بقاعدة 70/30: 70% محتوى قيم و30% فقط بيع مباشر. استخدم جدول المحتوى الأسبوعي لضمان هذا التنوع تلقائياً.\"\n        },\n        exercises: [\n            {\n                title: \"بناء الهوية البصرية خلال 5 دقائق\",\n                description: \"افتح Canva واختر قالب غلاف فيسبوك جاهز، وعدّل الألوان والنص ليعبّر عن اسم مشروعك.\",\n                format: \"رفع ملف\"\n            },\n            {\n                title: \"تعبئة قسم النبذة\",\n                description: \"اكتب نص نبذة صفحتك في جملتين فقط: ماذا تبيع، لمن، وما الذي يميزك.\",\n                format: \"نصي\"\n            },\n            {\n                title: \"تعبئة جدول المحتوى الأسبوعي\",\n                description: \"اكتب فكرة منشور واحدة محددة (بعنوان فعلي) لكل يوم من أيام الأسبوع القادم.\",\n                format: \"نصي\"\n            },\n            {\n                title: \"تصميم منشور بيع بورقة وقلم قبل التنفيذ\",\n                description: \"ارسم تخطيطاً بسيطاً (Storyboard): أين الصورة، ماذا العنوان، وأين رقم الطلب.\",\n                format: \"رفع ملف\"\n            }\n        ],\n        expectedQuestions: [\n            {\n                q: \"ما اسم الصفحة الأفضل: اسمي الشخصي أم اسم تجاري؟\",\n                a: \"اسم تجاري دائماً، حتى لو بسيطاً، لأنه يمنحك مصداقية ومساحة للنمو لاحقاً.\"\n            },\n            {\n                q: \"هل أحتاج شعاراً احترافياً مدفوعاً من مصمم؟\",\n                a: \"لا في هذه المرحلة، Canva كافٍ تماماً لأول 3 أشهر على الأقل.\"\n            }\n        ],\n        aiPrompt: \"اكتب لي نص نبذة قصيرة لصفحة فيسبوك تبيع [منتجك] في السودان، بأسلوب ودود وجملتين فقط، مع كلمات مفتاحية يبحث بها العميل السوداني.\",\n        homework: \"أنشئ صفحتك أو حسّنها بالكامل: غلاف احترافي، صورة شخصية مناسبة، نبذة واضحة بجملتين. ثم انشر أول منشورين فعليين وسجّل لقطات شاشة لهما.\",\n        tool: {\n            name: \"Canva\",\n            description: \"أقوى أداة مجانية لتصميم الغلاف والمنشورات والفيديوهات بقوالب جاهزة تعدّلها بخطوات بسيطة.\",\n            url: \"https://www.canva.com\"\n        },\n        selfCheck: [\n            \"صفحتي تحتوي على صورة شخصية وغلاف ونبذة كاملة ومكتوبة\",\n            \"صممت غلاف فيسبوك على كانفا ورفعته فعلياً\",\n            \"جهزت جدول محتوى مكتوب لأسبوع كامل بمنشورات محددة\",\n            \"نشرت منشورين فعليين على الأقل على صفحتي\",\n            \"أفهم قاعدة 70/30 في المحتوى\",\n            \"أنجزت واجب هذه الوحدة\"\n        ],\n        projectComponent: \"الصفحة الرسمية بكامل عناصرها (اسم، صورة، غلاف، نبذة) + أول منشورين فعليين منشورين.\",\n        pathNotes: {\n            beginner: \"اجلس فعلياً بجانب كل خطوة دقيقة واحدة على الأقل للتأكد أنك ضغطت زر \\\"نشر\\\" لا \\\"حفظ كمسودة\\\" فقط — خطأ شائع جداً في هذا المستوى.\",\n            intermediate: \"ركّز وقتك على جدول المحتوى الأسبوعي وتحديد Hook وCTA لكل منشور بدل التوقف الطويل عند الشكل البصري.\",\n            professional: \"ادمج تمرين التصوير مع بناء الصفحة في نفس الجلسة، ولا تفصل بينهما زمنياً — جدولك مكثف.\"\n        }\n    },\n    {\n        id: 4,\n        week: 2,\n        title: \"إعلانات فيسبوك المدفوعة ومجموعات التفاعل\",\n        duration: \"90 دقيقة\",\n        icon: \"Megaphone\",\n        objective: \"بنهاية هذه الوحدة، تكون قادراً على شرح آلية الاستهداف، وقد صممت إعلاناً كاملاً جاهزاً للتنفيذ.\",\n        tip: \"استخدام أرقام تنتهي بـ9 أو 5 يخلق إحساساً نفسياً بسعر أقل (4900 بدل 5000).\",\n        expertTip: \"استخدام أرقام تنتهي بـ9 أو 5 بدل الأرقام الصحيحة (4900 بدل 5000) يخلق إحساساً نفسياً بسعر أقل رغم أن الفارق ضئيل — أسلوب مثبت في سلوك المستهلك السوداني.\",\n        openingScript: \"هذه الوحدة تُدرَّس بطرق مختلفة تماماً حسب مسارك، فتأكد من أنك تعرف مستواك قبل البدء بها.\",\n        sections: [\n            {\n                heading: \"مبادئ الاستهداف — اصطاد في المكان الصحيح\",\n                body: \"فيسبوك يتيح الاستهداف حسب الموقع الجغرافي، العمر والجنس، الاهتمامات، والسلوك. عند محدودية الميزانية — وهذا الوضع الطبيعي للمبتدئ — ركّز على استهداف دقيق وضيق بدلاً من استهداف عام واسع. \\\"نساء 25-35 سنة في الخرطوم مهتمات بالتجميل\\\" أفضل بكثير من \\\"نساء في السودان\\\". كلما ضاق الاستهداف، قلّت التكلفة وزادت جودة النقرات.\"\n            },\n            {\n                heading: \"نصائح الإعلانات الناجحة — ابدأ صغيراً واختبر\",\n                body: \"ابدأ بميزانيات صغيرة: 5 إلى 10 دولارات يومياً كافية تماماً للتجربة. اختبار A/B هو أقوى تقنية: أنشئ إعلانين مختلفين واسمح لفيسبوك بتوزيع الميزانية بينهما، ثم بعد يومين أو ثلاثة أوقف الأضعف وضاعف الأقوى. راقب معدل النقرات CTR (المقبول 2% فأعلى)، وتكلفة النقرة CPC (كلما قلّت كان أفضل)، ومعدل التحويل (أهم مؤشر لأنه يعني مبيعات حقيقية). إعادة الاستهداف لمن تفاعل مع منشوراتك العضوية أرخص وأقوى نتيجة.\"\n            },\n            {\n                heading: \"المجموعات كأداة بناء مجتمع — عملاؤك الدائمون\",\n                body: \"المجموعة مختلفة عن الصفحة: الصفحة بث أحادي الاتجاه، والمجموعة بث ثنائي الاتجاه يخلق مجتمعاً حقيقياً. انشر فيها عروضاً حصرية لأعضائها، دعماً مباشراً للعملاء، واجمع آراءهم حول منتجات جديدة. هدفك الوصول إلى 200-500 عضو خلال الأشهر الأولى، وهذا كافٍ لتحقيق مبيعات منتظمة أسبوعياً.\"\n            }\n        ],\n        caseStudy: {\n            title: \"الإعلان الواسع مقابل الإعلان الدقيق\",\n            story: \"بائعة إكسسوارات في الخرطوم أنفقت 35 دولاراً باستهداف واسع (\\\"نساء في السودان، 18-45\\\") وحصلت على 12 ألف مشاهدة و400 نقرة لكن صفر مبيعات. في المرة الثانية، ضيّقت الاستهداف (\\\"نساء 25-35 في الخرطوم، مهتمات بالموضة\\\") بنفس المبلغ على 5 أيام، فحصلت على 3 آلاف مشاهدة فقط لكن 80 نقرة و7 عمليات بيع فعلية غطت الميزانية وأربحت.\",\n            analysis: \"الفرق لم يكن في المبلغ الإجمالي بل في دقة الاستهداف. 1000 مشاهدة من شخص مناسب أفضل من 100 ألف مشاهدة من شخص غير مناسب.\"\n        },\n        goldenRule: \"الميزانية الصغيرة مع الاستهداف الدقيق تتفوق دائماً على الميزانية الكبيرة مع الاستهداف الواسع.\",\n        commonMistake: {\n            problem: \"إيقاف الإعلان بعد يوم واحد فقط بسبب قلة النتائج الفورية، دون إعطائه فرصة كافية لجمع بيانات.\",\n            solution: \"امنح كل إعلان 3 إلى 4 أيام على الأقل قبل تقييم أدائه. إذا لم يتحسن الأداء بعد 4 أيام، غيّر الصورة أو النص ثم جرّب مرة أخرى.\"\n        },\n        exercises: [\n            {\n                title: \"تصميم إعلان كامل على ورقة\",\n                description: \"ارسم تخطيط الإعلان: الصورة، النص الأساسي، الدعوة لاتخاذ إجراء، والفئة العمرية والمدينة والاهتمام المستهدف.\",\n                format: \"نصي\"\n            },\n            {\n                title: \"حساب الميزانية المصغرة\",\n                description: \"احسب: لو خصصت 5 دولارات يومياً لمدة 7 أيام، كم الإجمالي بالجنيه السوداني؟ وكم عملية بيع تحتاجها لتغطية التكلفة؟\",\n                format: \"نصي\"\n            },\n            {\n                title: \"اختبار A/B ذهني\",\n                description: \"اختر صورتين مختلفتين لنفس المنتج، واكتب توقعك: أيهما ستحقق نقرات أكثر ولماذا؟\",\n                format: \"نصي\"\n            }\n        ],\n        expectedQuestions: [\n            {\n                q: \"لماذا نبدأ بميزانية صغيرة جداً؟\",\n                a: \"لأن الهدف الأول هو التعلم من البيانات لا الربح الفوري؛ الميزانية الكبيرة على استهداف خاطئ تُضيَّع بالكامل.\"\n            },\n            {\n                q: \"كم يوماً يجب أن أنتظر قبل الحكم على إعلان؟\",\n                a: \"3 إلى 4 أيام على الأقل بميزانية ثابتة قبل أي تعديل أو إيقاف.\"\n            }\n        ],\n        aiPrompt: \"اكتب لي 3 نصوص إعلانية قصيرة مختلفة لمنتج [منتجك] موجهة لجمهور سوداني، كل نص بأسلوب مختلف: عاطفي، عملي، وطارئ/محدود الكمية.\",\n        homework: \"صمم مخطط إعلان كامل جاهز للتنفيذ: صورة، نص إعلاني، دعوة واضحة، واستهداف محدد. إذا كانت لديك ميزانية صغيرة، نفّذه فعلياً وسجّل النتائج بعد 4 أيام.\",\n        tool: {\n            name: \"Meta Business Suite\",\n            description: \"أداة مجانية من فيسبوك لإدارة صفحتك وجدولة المنشورات وإنشاء الإعلانات المدفوعة ومتابعة نتائجها.\",\n            url: \"https://business.facebook.com\"\n        },\n        selfCheck: [\n            \"أفهم الفرق بين CTR (معدل النقرات) و CPC (تكلفة النقرة)\",\n            \"صممت مخطط إعلان كامل يتضمن صورة ونص واستهداف\",\n            \"حددت استهدافاً دقيقاً (مدينة + عمر + اهتمام) وليس استهدافاً عاماً\",\n            \"أحسبت الميزانية المطلوبة وعدد المبيعات اللازمة لتغطيتها\",\n            \"أفهم لماذا يجب انتظار 3-4 أيام قبل تقييم الإعلان\",\n            \"أنجزت واجب هذه الوحدة\"\n        ],\n        projectComponent: \"مخطط إعلان كامل (أو إعلان فعلي مُشغَّل حسب مسارك) جاهز ضمن ملف متجرك.\",\n        pathNotes: {\n            beginner: \"لا تفتح مدير الإعلانات إطلاقاً في هذه المرحلة. بدلاً منه نفّذ تمرين التعاون المجاني بالكامل: اتفق مع صفحة مكمّلة على تبادل نشر مجاني.\",\n            intermediate: \"جهّز الإعلان بورقة وقلم هذا الأسبوع فقط، والتشغيل الفعلي يتأجل لمنتصف الأسبوع الثالث (اليوم 17-18).\",\n            professional: \"شغّل حملتين مختلفتين فعلياً (اختبار A/B) في نفس الجلسة، ولا تكتفِ بحملة واحدة.\"\n        }\n    }\n];\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./src/data/units-3-4.ts\n");

