eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   units56: () => (/* binding */ units56)\n/* harmony export */ });\nconst units56 = [\n    {\n        id: 5,\n        week: 3,\n        title: \"استراتيجية تيك توك والمحتوى الفيروسي\",\n        duration: \"90 دقيقة\",\n        icon: \"Video\",\n        objective: \"بنهاية هذه الوحدة، تكون قد صوّرت أول فيديو تيك توك فعلي بهاتفك، وفهمت كيفية ربط الحساب بواتساب لتحويل المشاهدات إلى طلبات.\",\n        tip: \"الفيديوهات التي يُعاد مشاهدتها كاملة (Loop) تُعامَل من الخوارزمية كإشارة قوة أهم من عدد المشاهدات.\",\n        expertTip: \"الأسبوع الثالث هو أخطر أسبوع في أي دورة؛ فيه يبدأ الحماس بالانخفاض لأن النتائج الملموسة غالباً لم تظهر بعد. إذا شعرت أن شيئاً لم يتغير رغم كل ما نشرته، فهذا طبيعي ومتوقع إحصائياً وليس فشلاً منك — الخوارزميات تحتاج من 15 إلى 20 يوماً لتتعرف على هوية محتواك. المطلوب الآن مضاعفة الاستمرارية لا التوقف.\",\n        openingScript: \"صوّر فيديو تجريبي أمام نفسك أولاً، حتى لو بسيطاً، لكسر الخجل — كثيرون يخافون الظهور أكثر من خوفهم من الفشل التجاري.\",\n        sections: [\n            {\n                heading: \"لماذا تيك توك الآن — أسرع منصة نمواً في السودان\",\n                body: \"تيك توك سجل نمواً بنسبة 26.3% خلال عام واحد، وهو الأعلى بين كل المنصات. الأهم أن خوارزميته تكافئ المحتوى الأصيل بغض النظر عن عدد المتابعين — حساب جديد بصفر متابع يمكن أن يحقق مئات آلاف المشاهدات إذا كان المحتوى جذاباً. تيك توك هو مرحلة الاكتشاف في رحلة العميل: يصادف فيديوك أثناء التصفح، ثم ينتقل لصفحتك على فيسبوك لمعرفة المزيد، ثم يتواصل معك على واتساب للشراء.\"\n            },\n            {\n                heading: \"أنواع المحتوى الأفضل أداءً\",\n                body: \"قبل وبعد: مثالي لمنتجات التجميل والتنظيف، فالتغيير البصري يثبت النتيجة بشكل لا يُجادل. يوم في حياة رائد أعمال: يبني ثقة هائلة لأنه يثبت أن مشروعك حقيقي. حل مشكلة في 60 ثانية: يجعل المشاهد يحفظ الفيديو ويعود إليه. كشف سر أو طريقة عمل شيء: يجعل الناس تتابعك لأنها تتوقع معلومات قيمة. ردود فعل العملاء الحقيقية: أقوى من أي إعلان. ترندات الصوت مع لمسة العلامة التجارية: تجعل الخوارزمية تدمج فيديوك مع الترند.\"\n            },\n            {\n                heading: \"أساسيات التصوير وربط تيك توك بواتساب\",\n                body: \"الإضاءة هي أهم عامل — صوّر بإضاءة طبيعية قدر الإمكان. استخدم حاملاً ثلاثي القوائم للاستقرار، واجعل الخلفية نظيفة، وركّز في أول 3 ثوانٍ لأن تيك توك يعطيك هذه الفرصة فقط قبل أن يتخطى المشاهد الفيديو. أضف نصوصاً عربية واضحة لأن كثيرين يشاهدون بدون صوت. ثم اربط بواتساب: ضع رقمك في البايو بوضوح، استخدم عبارات دعوة واضحة (\\\"اسحب للأعلى للطلب\\\")، ورد على كل تعليق موجهاً صاحبه لواتساب.\"\n            }\n        ],\n        caseStudy: {\n            title: \"فيديو بسيط بمشاهدات غير متوقعة\",\n            story: \"تاجر أعشاب في أم قرقر صوّر فيديو 45 ثانية عن عشبة محلية معروفة بأسلوب سوداني مبسط، مع ترند صوتي شائع، بهاتفه فقط بجانب النافذة صباحاً. حصل الفيديو على أكثر من 50 ألف مشاهدة خلال يومين، وتلقى أكثر من 200 رسالة واتساب تطلب العشبة.\",\n            analysis: \"النجاح جاء من ثلاثة عوامل: معلومة مفيدة وحقيقية لا ترويج مباشر، استخدام ترند صوتي شائع جعل الخوارزمية توصله لجمهور أوسع، وأسلوب سوداني بسيط جعل المشاهد يشعر بالقرب والمصداقية.\"\n        },\n        goldenRule: \"لا تنتظر معدات احترافية لتبدأ، هاتفك وإضاءة النهار كافيان لأول 50 فيديو. المحتوى الجيد أهم من الكاميرا الغالية.\",\n        commonMistake: {\n            problem: \"إطالة المقدمة بالترحيب والتعريف بالنفس قبل الوصول للمحتوى، مما يفقد المشاهد خلال الثواني الأولى.\",\n            solution: \"ابدأ الفيديو مباشرة بالمشكلة أو الفائدة أو المفاجأة، واترك التعريف بنفسك للنهاية إن لزم الأمر.\"\n        },\n        exercises: [\n            {\n                title: \"تصوير فيديو 60 ثانية فوراً\",\n                description: \"اختر فكرة واحدة من أنواع المحتوى وصوّرها فعلياً بهاتفك الآن، بحد أقصى 3 محاولات.\",\n                format: \"رفع ملف\"\n            },\n            {\n                title: \"كتابة أول 3 ثوانٍ (الجملة الجذابة)\",\n                description: \"اكتب جملة الافتتاح (Hook) التي ستجذب المشاهد قبل أن يتخطى الفيديو.\",\n                format: \"نصي\"\n            },\n            {\n                title: \"كتابة نص البايو وربطه بواتساب\",\n                description: \"اكتب نص البايو كاملاً: وصف قصير، رقم واتساب واضح، وعبارة دعوة واحدة، بحد أقصى 3 أسطر.\",\n                format: \"رابط\"\n            }\n        ],\n        expectedQuestions: [\n            {\n                q: \"وجهي يظهر في الفيديو، ألا يوجد خصوصية أفضل؟\",\n                a: \"يمكن تصوير المنتج فقط دون ظهور الوجه في البداية، لكن الفيديوهات التي يظهر فيها صاحب المشروع تحقق ثقة أعلى بشكل عام.\"\n            },\n            {\n                q: \"كم مرة يجب أن أنشر أسبوعياً؟\",\n                a: \"3 مرات على الأقل أسبوعياً كحد أدنى مطلق لإعطاء الخوارزمية فرصة حقيقية لاختبار المحتوى.\"\n            }\n        ],\n        aiPrompt: \"اقترح لي 5 أفكار فيديو تيك توك مدة كل منها أقل من 60 ثانية لمنتج [منتجك]، مع جملة افتتاح جذابة (Hook) لكل فكرة لا تتجاوز 10 كلمات. نوّع الأفكار: قبل وبعد، حل مشكلة، كشف سر، يوم في حياة، ورد فعل عميل.\",\n        homework: \"انشر 3 فيديوهات فعلية على تيك توك خلال هذا الأسبوع، وسجّل لكل فيديو عدد المشاهدات والإعجابات والتعليقات ورسائل واتساب الناتجة.\",\n        tool: {\n            name: \"CapCut\",\n            description: \"أفضل تطبيق مجاني لتحرير الفيديوهات القصيرة، يتيح قص الفيديو وإضافة نصوص عربية وموسيقى مجاناً.\",\n            url: \"https://www.capcut.com\"\n        },\n        selfCheck: [\n            \"صورت فيديو واحداً فعلياً بهاتفي (حتى لو بسيط)\",\n            \"كتبت جملة افتتاح (Hook) لا تتجاوز 3 ثوانٍ\",\n            \"أضفت رقم واتساب في البايو أو التعليق المثبت\",\n            \"نشرت 3 فيديوهات فعلية على تيك توك\",\n            \"أفهم لماذا أول 3 ثوانٍ هي الأهم\",\n            \"أنجزت واجب هذه الوحدة\"\n        ],\n        projectComponent: \"عدد الفيديوهات المطلوب حسب مسارك (15 للمطلق، 10 للمتوسط، 8 عالية الجودة للمحترف) منشور فعلياً.\",\n        pathNotes: {\n            beginner: \"لا تفكر في الخوارزمية إطلاقاً في هذا المستوى. فقط \\\"صوّر وانشر، والتطبيق سيهتم بالباقي\\\".\",\n            intermediate: \"افهم مفهوم معدل الاستبقاء ببساطة (هل يكمل الناس مشاهدة الفيديو أم يغلقونه بسرعة) واربطه بجملة الافتتاح.\",\n            professional: \"استخدم مفهوم السلسلة (Series) — 3 فيديوهات مترابطة تُنشر بفارق ساعات، بدل فيديو واحد منفرد.\"\n        }\n    },\n    {\n        id: 6,\n        week: 3,\n        title: \"واتساب للأعمال وبناء قاعدة العملاء\",\n        duration: \"90 دقيقة\",\n        icon: \"MessageCircle\",\n        objective: \"بنهاية هذه الوحدة، تكون قد فعّلت واتساب للأعمال، وأنشأت كتالوجاً فعلياً، وحاكيت محادثة بيع.\",\n        tip: \"الرسائل الصوتية القصيرة (أقل من 20 ثانية) تبني ثقة أسرع من الرسالة المكتوبة.\",\n        expertTip: \"الرسائل الصوتية القصيرة (أقل من 20 ثانية) في الرد على استفسار سعر تبني ثقة أسرع من الرسالة المكتوبة، لأنها تعطي إحساساً بوجود شخص حقيقي خلف الحساب.\",\n        openingScript: \"افتح واتساب للأعمال أمام نفسك الآن وأنشئ منتجاً واحداً في الكتالوج فعلياً خلال هذه الجلسة، لا كواجب لاحق.\",\n        sections: [\n            {\n                heading: \"لماذا واتساب هو الأهم في السودان\",\n                body: \"عالمياً يفتح 84.1% من مستخدمي واتساب التطبيق يومياً، وفي السودان هو المنصة الأساسية لإتمام عمليات البيع. واتساب للأعمال يوفر ميزات مجانية بالكامل: ردود آلية ترحيبية، رسائل سريعة جاهزة للأسئلة المتكررة، تصنيف المحادثات، وكتالوج منتجات مدمج يعمل كمتجر مصغر. العميل قد يكتشف منتجك على تيك توك ويتابع صفحتك على فيسبوك، لكن عندما يريد السؤال عن السعر أو التوصيل، يفتح واتساب — فكل ما سبق هو تمهيد لهذه اللحظة.\"\n            },\n            {\n                heading: \"إعداد الكتالوج وجمع العملاء\",\n                body: \"الكتالوج يعمل كمتجر مصغر: لكل منتج صورة واضحة، وصف مختصر بالسعر، وزر طلب مباشر، يوفر عليك إرسال الصور يدوياً لكل عميل. لإضافة منتج: افتح إعدادات واتساب للأعمال، اختر \\\"كتالوج الأعمال\\\"، ثم \\\"إضافة منتج\\\" بصورة واسم وسعر ووصف. لجمع أرقام العملاء: الإعلانات الموجهة مباشرة لواتساب (أقوى طريقة)، عرض مجاني مقابل رقم الهاتف، زر واتساب على كل منشور، وتشجيع العملاء الحاليين على مشاركة رقمك.\"\n            },\n            {\n                heading: \"إدارة المحادثات باحتراف — الفرق بين البيع وضياع العميل\",\n                body: \"الرد السريع هو أهم عامل في إتمام البيع: قاعدة ذهبية، رد خلال 5 دقائق كحد أقصى. الردود السريعة الجاهزة توفر وقتك وتضمن دقة المعلومة لكل عميل. صنّف كل محادثة إلى: جديد، قيد المتابعة، تم البيع، ومتابعة لاحقة، لتمنع نفسك من نسيان أي عميل محتمل. بعد 3 أيام من التوصيل، أرسل رسالة قصيرة تسأل عن رضا العميل — هذا يبني ولاء ويفتح الباب لتقييمات إيجابية.\"\n            }\n        ],\n        caseStudy: {\n            title: \"الرد المتأخر الذي كلّف 15 عميلاً\",\n            story: \"صاحب متجر أحذية في كسلا كان يرد على واتساب مرة واحدة مساءً فقط. بعد شهر، اكتشف عبر إحصائيات واتساب للأعمال أن أكثر من 15 رسالة استفسار وصلت خلال ساعات العمل ولم يُرد عليها إلا بعد 6-8 ساعات، ومعظم أصحابها اشتروا من منافس أسرع. بعد أن بدأ يرد خلال 5 دقائق باستخدام الردود السريعة، تضاعفت مبيعاته الأسبوعية خلال أسبوعين.\",\n            analysis: \"سرعة الرد ليست تفصيلاً ثانوياً بل هي العامل الحاسم بين البيع وضياع العميل في التجارة الأونلاين السودانية. العميل لا ينتظر لأن لديه خيارات أخرى.\"\n        },\n        goldenRule: \"العميل الذي ينتظر ردك أكثر من ساعة غالباً ما يكون قد اشترى من غيرك أو نسى الأمر.\",\n        commonMistake: {\n            problem: \"إرسال رسائل ترويجية متكررة ومزعجة لكل أرقام جهات الاتصال، مما يتحول من تسويق إلى إزعاج ويجعل الناس تحظر الرقم.\",\n            solution: \"صنّف قائمة العملاء إلى فعليين ومهتمين. راسل الفئة الأولى كل أسبوعين بعرض جديد. للفئة الثانية، دعهم يتابعون صفحتك بدل مراسلتهم مباشرة.\"\n        },\n        exercises: [\n            {\n                title: \"بناء الكتالوج الآن — منتج حقيقي\",\n                description: \"أضف منتجاً واحداً فعلياً في الكتالوج: صورة واضحة، اسم، سعر بالجنيه، ووصف مختصر لا يتجاوز سطرين.\",\n                format: \"رفع ملف\"\n            },\n            {\n                title: \"محاكاة محادثة عميل صعب\",\n                description: \"بالتبادل مع زميل: أحدكم عميل يماطل بـ\\\"السعر غالي وسأفكر\\\"، والآخر بائع يرد باحتراف دون إلحاح مزعج.\",\n                format: \"محاكاة\"\n            },\n            {\n                title: \"كتابة رسالة الترحيب الآلية\",\n                description: \"اكتب نص رسالة ترحيب تلقائية لا تتجاوز 3 أسطر: من أنت، ماذا تبيع، وكيف يطلب العميل.\",\n                format: \"نصي\"\n            }\n        ],\n        expectedQuestions: [\n            {\n                q: \"العميل يسألني ثم يختفي، ماذا أفعل؟\",\n                a: \"أرسل متابعة واحدة مهذبة بعد يومين، وإن لم يرد، صنّفه \\\"متابعة لاحقة\\\" ولا تلح أكثر من ذلك.\"\n            },\n            {\n                q: \"هل أرد بنفس السرعة على كل الرسائل بلا استثناء؟\",\n                a: \"نعم قدر الإمكان، فالسرعة في الرد أهم من كمال صياغة الرد نفسه.\"\n            }\n        ],\n        aiPrompt: \"اكتب لي 5 ردود جاهزة على واتساب بالعربية السودانية البسيطة للأسئلة الشائعة في مشروع يبيع [منتجك]: السعر، طرق الدفع، مدة التوصيل، إمكانية الاستبدال، والمقاسات. كل رد لا يتجاوز 3 أسطر.\",\n        homework: \"فعّل كتالوج واتساب بثلاثة منتجات حقيقية، اكتب رسالة ترحيب آلية، واحفظ 3 ردود سريعة للأسئلة المتكررة.\",\n        tool: {\n            name: \"WhatsApp Business\",\n            description: \"تطبيق مجاني مصمم خصيصاً لأصحاب المشاريع الصغيرة: كتالوج، ردود آلية، وتصنيف محادثات.\",\n            url: \"https://business.whatsapp.com\"\n        },\n        selfCheck: [\n            \"فعّلت تطبيق واتساب للأعمال على هاتفي\",\n            \"أضفت 3 منتجات على الأقل في الكتالوج بصور وأسعار\",\n            \"كتبت رسالة ترحيب آلية لا تتجاوز 3 أسطر\",\n            \"جربت محاكاة الرد على عميل متردد\",\n            \"حفظت ردود سريعة للأسئلة المتكررة\",\n            \"أنجزت واجب هذه الوحدة\"\n        ],\n        projectComponent: \"كتالوج واتساب فعّال بـ3 منتجات على الأقل + رسالة ترحيب آلية مفعّلة.\",\n        pathNotes: {\n            beginner: \"ستحتاج مساعدة يدوية في إضافة أول منتج للكتالوج خطوة بخطوة، فواجهة الكتالوج قد تكون مربكة لأول مرة.\",\n            intermediate: \"ركّز على تصنيف المحادثات الأربعة (جديد/متابعة/تم البيع/لاحقاً) كأداة تحليلية لا تنظيمية فقط.\",\n            professional: \"انتقل مباشرة لتصميم Chat Flow متكامل (تسلسل ردود آلية متفرعة حسب اختيار العميل) بدل الردود الفردية.\"\n        }\n    }\n];\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./src/data/units-5-6.ts\n");

