eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   units78: () => (/* binding */ units78)\n/* harmony export */ });\nconst units78 = [\n    {\n        id: 7,\n        week: 4,\n        title: \"ربط المنصات الثلاث وإدارة العمليات والدفع\",\n        duration: \"90 دقيقة\",\n        icon: \"Network\",\n        objective: \"بنهاية هذه الوحدة، تكون قد صممت قمع مبيعات متكاملاً، وأنشأت جدول تتبع فعلياً، وحددت سياسة دفع.\",\n        tip: \"عند تردد العميل بسبب السعر، أضف قيمة (توصيل مجاني، هدية، ضمان) بدلاً من تخفيض السعر.\",\n        expertTip: \"عند تردد العميل بسبب السعر، لا تخفّض السعر فوراً؛ أضف قيمة (توصيل مجاني، هدية بسيطة، ضمان استبدال) فهذا يحافظ على قيمة المنتج بدل تعويد العميل على المساومة الدائمة.\",\n        openingScript: \"ارسم قمع المبيعات أمام نفسك، واشرح بصوت عالٍ كيف سينتقل عميلك بين المنصات الثلاث تحديداً في مشروعك.\",\n        sections: [\n            {\n                heading: \"قمع المبيعات المتكامل — كيف يتحول المتصفح لمشتري\",\n                body: \"المرحلة الأولى — الاكتشاف (تيك توك): لا تحاول البيع هنا، الهدف لفت الانتباه وبناء الفضول. المرحلة الثانية — التعمق وبناء الثقة (فيسبوك): العميل يرى تقييمات ومنشورات متنوعة ويبدأ يثق. المرحلة الثالثة — الشراء والمتابعة (واتساب): هنا يتم القرار النهائي، وسرعة ردك تحدد إن سيكمل أو يتراجع. استخدم كل منصة لغرضها الطبيعي بدل تكرار نفس المحتوى في كل مكان.\"\n            },\n            {\n                heading: \"إدارة الطلبات والمخزون — النظام الذي ينقذك\",\n                body: \"سجّل كل طلب في جدول بسيط: الاسم، المنتج، السعر، العنوان، حالة الطلب، وتاريخ التوصيل المتوقع، لتمنع نفسك من نسيان أي طلب. حدد أياماً ثابتة للتوصيل (مثلاً \\\"الثلاثاء والجمعة\\\") لتقليل رسائل الاستفسار المتكررة. أبلغ العميل بموعد متوقع فور تأكيد الطلب، وتابع بعد التوصيل للتأكد من رضاه.\"\n            },\n            {\n                heading: \"طرق الدفع وخدمة العملاء كميزة تنافسية\",\n                body: \"الدفع عند الاستلام هو الأكثر شيوعاً في السودان؛ العميل يفضل رؤية المنتج قبل الدفع. اكتب سياسة الدفع بوضوح من أول لحظة، ولا تسلّم المنتج قبل استلام المبلغ إلا لعملاء موثوقين بعلاقة سابقة. تعامل مع كل عميل كأنه الوحيد: عند الشكوى، استمع باحترام وقدّم حلاً حقيقياً. اطلب تقييماً من العملاء الراضين — التقييمات الحقيقية تساوي آلاف الإعلانات في السوق السوداني حيث الثقة هي العملة الأهم.\"\n            }\n        ],\n        caseStudy: {\n            title: \"الفوضى التي أوقفت النمو\",\n            story: \"صاحبة مشروع حلويات في الأبيض كانت تدير طلباتها من الذاكرة. مع زيادة الطلبات إلى 15-20 أسبوعياً، بدأت تخلط العناوين وتنسى الطلبات. في أسبوعين فقدت 8 عملاء وكتب بعضهم تقييمات سلبية. بعد تطبيق جدول تتبع بسيط على جداول جوجل وتحديد يومين ثابتين للتوصيل، عادت الأمور للاستقرار.\",\n            analysis: \"النمو بدون نظام تتبع لا يتحول فقط إلى فوضى بل يضر بسمعتك. جدول تتبع بسيط ومجاني يمنع كل هذا ويتيح لك النمو بثقة.\"\n        },\n        goldenRule: \"النمو السريع بدون نظام تتبع يتحول إلى فوضى تخسرك عملاءك. جدول واحد مجاني على جوجل ينقذ مشروعك.\",\n        commonMistake: {\n            problem: \"الاعتماد على الذاكرة لتتبع الطلبات والعناوين والمواعيد، وهو ما يعمل مؤقتاً لكنه ينهار مع النمو.\",\n            solution: \"خصص جدولاً واحداً فقط على جداول جوجل لكل الطلبات. لا يحتاج أن يكون معقداً — 6 أعمدة كافية، وحدّثه يومياً.\"\n        },\n        exercises: [\n            {\n                title: \"رسم قمع المبيعات الخاص بمشروعك\",\n                description: \"ارسم مخططاً بثلاث خطوات: تيك توك (اكتشاف) → فيسبوك (ثقة) → واتساب (شراء)، مع ماذا سيرى العميل في كل خطوة.\",\n                format: \"نصي\"\n            },\n            {\n                title: \"إنشاء جدول تتبع الطلبات فعلياً\",\n                description: \"أنشئ جدولاً على Google Sheets بالأعمدة: الاسم، الهاتف، المنتج، الكمية، السعر، العنوان، حالة الطلب، تاريخ الطلب.\",\n                format: \"رفع ملف\"\n            },\n            {\n                title: \"محاكاة عميل يماطل في الدفع\",\n                description: \"مثّل موقف عميل يطلب استلام المنتج أولاً والدفع لاحقاً دون علاقة سابقة، واكتب ردك بسياسة واضحة ومهذبة.\",\n                format: \"محاكاة\"\n            }\n        ],\n        expectedQuestions: [\n            {\n                q: \"عميل طلب التوصيل أولاً والدفع لاحقاً، ماذا أفعل؟\",\n                a: \"ارفض بلطف واشرح سياستك بوضوح، إلا إن كانت هناك علاقة ثقة سابقة موثقة معه.\"\n            },\n            {\n                q: \"كيف أتابع عشرات الطلبات دون نسيان؟\",\n                a: \"جدول واحد فقط على Google Sheets يُحدَّث لحظياً، ولا اعتماد على الذاكرة مهما قلّ العدد.\"\n            }\n        ],\n        aiPrompt: \"صمم لي هيكل جدول Google Sheets بسيط لتتبع طلبات مشروع صغير في السودان، مع الأعمدة المناسبة وأمثلة على حالات الطلب الممكنة.\",\n        homework: \"جهّز جدول تتبع الطلبات الفعلي على جداول جوجل واكتب سياسة الدفع النهائية. أضف حالة طلب وهمي واحد للجدول كتجربة.\",\n        tool: {\n            name: \"Google Sheets\",\n            description: \"أداة مجانية من جوجل لإنشاء جداول تتبع الطلبات والعملاء والمخزون، تعمل على الهاتف وتحفظ تلقائياً.\",\n            url: \"https://sheets.google.com\"\n        },\n        selfCheck: [\n            \"رسمت قمع المبيعات الخاص بمشروعي بثلاث خطوات واضحة\",\n            \"أنشأت جدول تتبع طلبات فعلياً على جداول جوجل\",\n            \"كتبت سياسة دفع واضحة تشمل طرق الدفع وشروط الاستبدال\",\n            \"أفهم لماذا المتابعة بعد البيع مهمة جداً\",\n            \"أنجزت واجب هذه الوحدة\"\n        ],\n        projectComponent: \"جدول تتبع طلبات فعلي مستخدم + سياسة دفع مكتوبة بوضوح.\",\n        pathNotes: {\n            beginner: \"بسّط الجدول لأقصى درجة: 4 أعمدة فقط (الاسم، المنتج، الحالة، الهاتف)، فالجداول المعقدة تخيفك عن استخدامها أصلاً.\",\n            intermediate: \"أضف عمود \\\"مصدر العميل: تيك توك/فيسبوك/إحالة\\\" لبدء تحليل أي منصة تجلب عملاء أكثر فعلياً.\",\n            professional: \"أضف تمرين حساب تكلفة الاكتساب لكل مصدر عميل على حدة، تمهيداً لحساب ROI في الوحدة القادمة.\"\n        }\n    },\n    {\n        id: 8,\n        week: 4,\n        title: \"الأدوات، القياس، وإطلاق المشروع النهائي\",\n        duration: \"90 دقيقة\",\n        icon: \"Rocket\",\n        objective: \"بنهاية هذه الوحدة، تكون قد أتقنت الأدوات المجانية، وفهمت المصطلحات الرقمية، وقدّمت مشروعك التراكمي.\",\n        tip: \"تجنب تغيير الأسعار بشكل متكرر؛ الثبات يبني ثقة أطول.\",\n        expertTip: \"تجنّب تغيير الأسعار المعلنة بشكل متكرر ومفاجئ؛ الثبات النسبي في السعر يبني ثقة أطول أمداً من مكاسب قصيرة المدى ناتجة عن رفع مفاجئ.\",\n        openingScript: \"هذه الجلسة عرض وتتويج لا تعليم جديد. خصص 3 دقائق فقط لعرض متجرك الرقمي المصغر كاملاً.\",\n        sections: [\n            {\n                heading: \"الأدوات المجانية التي تحتاجها\",\n                body: \"Canva لتصميم الصور والغلافات والمنشورات. CapCut لتحرير الفيديوهات القصيرة وإضافة النصوص العربية. Google Sheets لإدارة الطلبات والعملاء والمخزون. Meta Business Suite لإدارة صفحتك وجدولة المنشورات وإعلاناتك. Linktree لربط جميع روابطك في مكان واحد بالبايو. Lightroom لتعديل الصور وتحسين إضاءتها وألوانها. كلها مجانية بالكامل وتكفي لأول 3 أشهر على الأقل.\"\n            },\n            {\n                heading: \"المصطلحات التي يجب إتقانها\",\n                body: \"CTR (معدل النقرات): نسبة من شاهدوا ونقروا، المقبول 2% فأعلى. CPC (تكلفة النقرة): كلما قلّ كان أفضل. ROI (العائد على الاستثمار): (الربح − التكلفة) ÷ التكلفة × 100. Conversion (التحويل): كل إجراء تريده من العميل. Engagement (التفاعل): مجموع الإعجابات والتعليقات والمشاركات. Reach (الوصول): عدد الأشخاص المختلفين الذين شاهدوا منشورك. Lead (العميل المحتمل): شخص أبدى اهتماماً لكن لم يشترِ بعد. Funnel (قمع المبيعات): رحلة العميل من الاكتشاف حتى الشراء. Algorithm (الخوارزمية): القواعد التي تحدد ماذا يرى المستخدم.\"\n            },\n            {\n                heading: \"مصادر التعلم المستمر — لا تتوقف بعد الورشة\",\n                body: \"التعلم المستمر هو الفرق بين من ينجح ومن يتوقف بعد الورشة. تابع قناة يوتيوب عربية واحدة متخصصة في التسويق الرقمي (لا تُكثر المصادر). تابع مجموعة أو اثنتين من مجموعات فيسبوك لريادة الأعمال السودانية وكن نشطاً فيها. جرّب دورة جوجل ديجيتال جاراج المجانية المعتمدة. تابع 3-5 حسابات ملهمة في مجالك وراقب كيف يتعاملون مع العملاء — التعلم بالملاحظة أقوى من التعلم النظري.\"\n            }\n        ],\n        caseStudy: {\n            title: \"التعلم المستمر الذي بنى مشروعاً مستقلاً\",\n            story: \"خريجة من دورة مشابهة في الخرطوم واظبت على متابعة قناة يوتيوب واحدة ومجموعة فيسبوك سودانية واحدة فقط، أسبوعياً. خلال 3 أشهر من نهاية الدورة، استمرت في التطوير دون أي دورة مدفوعة إضافية، حتى أصبح دخلها الشهري يتجاوز 3 أضعاف راتبها السابق.\",\n            analysis: \"السر لم يكن في كثرة المصادر بل في الاستمرارية على مصدر واحد والانضباط في التطبيق الفوري. 30 دقيقة أسبوعياً على مدار 3 أشهر — أقل من يوم عمل واحد — كانت كافية لبناء مشروع مستقل.\"\n        },\n        goldenRule: \"النجاح يحتاج صبراً واستمرارية أكثر من حاجته للكمال. ابدأ وحسّن وأنت تمشي.\",\n        commonMistake: {\n            problem: \"التوقف عن التعلم فور انتهاء الورشة، بافتراض أن ما تعلمته يكفي لبقية حياتك المهنية.\",\n            solution: \"خصص 30 دقيقة أسبوعياً فقط لمصدر تعلم واحد، ثابتة في موعد محدد، واجعلها جزءاً من جدولك مثل أي موعد مهم.\"\n        },\n        exercises: [\n            {\n                title: \"جولة سريعة على 3 أدوات\",\n                description: \"افتح Canva وCapCut وGoogle Sheets بالتتابع، وفي كل واحدة نفّذ إجراءً واحداً بسيطاً فعلياً.\",\n                format: \"نصي\"\n            },\n            {\n                title: \"اختبار المصطلحات الرقمية\",\n                description: \"بدون رجوع للمحتوى، اكتب تعريفاً من كلمة واحدة لكل من: CTR، CPC، ROI، Funnel، Lead.\",\n                format: \"نصي\"\n            },\n            {\n                title: \"عرض المشروع التراكمي النهائي\",\n                description: \"قدّم مشروعك الكامل: صفحة فيسبوك، حساب تيك توك، كتالوج واتساب، وأي تجربة إعلان مدفوع.\",\n                format: \"رفع ملف\"\n            }\n        ],\n        expectedQuestions: [\n            {\n                q: \"ماذا أفعل لو لم أحقق أي مبيعات حتى الآن؟\",\n                a: \"إكمال الملفات الرقمية بجودة عالية هو نجاح حقيقي بذاته، والمبيعات نتيجة طبيعية تتبع الاستمرارية لا الأسبوع الأول دائماً.\"\n            },\n            {\n                q: \"من أين أتعلم بعد انتهاء الورشة؟\",\n                a: \"حدد مصدرين فقط وثابتين وتابعهما أسبوعياً، فالتشتت بين مصادر كثيرة يوقف التعلم الفعلي.\"\n            }\n        ],\n        aiPrompt: \"بناءً على أن مشروعي هو [صف مشروعك في جملة]، اقترح لي 3 أهداف رقمية واضحة يمكن قياسها للشهر القادم.\",\n        homework: \"قدّم مشروعك التراكمي الكامل: صفحة فيسبوك بـ10 منشورات، 6 فيديوهات تيك توك، كتالوج بـ3 منتجات، وخطة أهداف مكتوبة للشهر القادم بأرقام محددة.\",\n        tool: {\n            name: \"Google Digital Garage\",\n            description: \"منصة مجانية من جوجل تقدم دورات معتمدة في أساسيات التسويق الرقمي مع شهادة إتمام مجانية.\",\n            url: \"https://learndigital.withgoogle.com/digitalgarage\"\n        },\n        selfCheck: [\n            \"أستطيع تعريف 5 مصطلحات رقمية على الأقل\",\n            \"قدّمت مشروعي التراكمي الكامل (صفحة + تيك توك + كتالوج)\",\n            \"حددت مصدرين فقط للتعلم المستمر وألزمت بهما\",\n            \"كتبت 3 أهداف رقمية واضحة للشهر القادم\",\n            \"أنجزت واجب هذه الوحدة\"\n        ],\n        projectComponent: \"تسليم المتجر الرقمي المصغر كاملاً بكل مكوناته + خطة أهداف الشهر القادم مكتوبة.\",\n        pathNotes: {\n            beginner: \"احتفِ بإكمال الملفات كإنجاز كامل ومستقل، ولا تقارن نتائجك بمستويات أخرى.\",\n            intermediate: \"اذكر رقم مبيعات فعلي محدد (لو تحقق) كجزء من عرضك، فهذا يرسّخ ثقافة القياس.\",\n            professional: \"اعرض رقم ROI الفعلي المحسوب ونقطة التعادل، فهذا هو مقياس نجاحك الحقيقي في هذا المستوى.\"\n        }\n    }\n];\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./src/data/units-7-8.ts\n");

